const ActorModal: React.FC<{ actorId: number; onClose: () => void }> = ({ actorId, onClose }) => {
    const [actor, setActor] = useState<any>(null);
    const [loading, setLoading] = useState(true);
    const { language } = useTranslation();
    const apiLang = 'en-US';

    useEffect(() => {
        const loadActor = async () => {
            try {
                const res = await fetch(`https://api.themoviedb.org/3/person/${actorId}?api_key=${API_KEY}&language=${apiLang}&append_to_response=combined_credits`);
                const data = await res.json();
                setActor(data);
            } catch (e) { console.error(e); }
            finally { setLoading(false); }
        };
        loadActor();
    }, [actorId, apiLang]);

    return (
        <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }} onClick={onClose} className="fixed inset-0 bg-black/95 z-[300] backdrop-blur-2xl flex items-center justify-center p-4 md:p-10">
            <motion.div initial={{ scale: 0.9, y: 50 }} animate={{ scale: 1, y: 0 }} exit={{ scale: 0.9, y: 50 }} onClick={e => e.stopPropagation()} className="bg-[#0c0c0c] border border-white/10 w-full max-w-5xl max-h-[90vh] rounded-[2.5rem] md:rounded-[4rem] overflow-hidden flex flex-col md:flex-row relative shadow-[0_0_100px_rgba(0,0,0,1)]">
                <button onClick={onClose} className="absolute top-6 right-6 z-50 p-3 bg-white/5 hover:bg-red-600 rounded-full transition-colors text-white"><X size={20}/></button>
                {loading ? <div className="w-full h-96 flex items-center justify-center"><Spinner /></div> : (
                    <>
                        <div className="w-full md:w-2/5 h-[40vh] md:h-auto relative overflow-hidden">
                            <img src={actor.profile_path ? `${IMAGE_BASE_URL}${actor.profile_path}` : 'https://i.imgur.com/4HoT8Yf.png'} className="w-full h-full object-cover" alt="" />
                            <div className="absolute inset-0 bg-gradient-to-t from-[#0c0c0c] via-transparent to-transparent md:bg-gradient-to-r" />
                        </div>
                        <div className="flex-1 p-8 md:p-16 overflow-y-auto scrollbar-hide text-right" dir={language === 'ku' ? 'rtl' : 'ltr'}>
                            <div className="flex items-center gap-2 mb-4">
                                <div className="w-1 h-4 bg-red-600 rounded-full" />
                                <span className="text-[10px] font-black uppercase tracking-[0.4em] text-gray-500">{language === 'ku' ? 'زانیاری ئەکتەر' : 'BIOMETRIC DATA'}</span>
                            </div>
                            <h2 className="text-4xl md:text-7xl font-[1000] uppercase italic tracking-tighter text-white mb-6 leading-none">{actor.name}</h2>
                            <div className="grid grid-cols-2 gap-4 mb-10">
                                <div className="bg-white/5 p-4 rounded-2xl border border-white/5">
                                    <p className="text-[8px] font-black text-red-500 uppercase mb-1">{language === 'ku' ? 'شوێنی لەدایکبوون' : 'Career Origin'}</p>
                                    <p className="text-xs font-bold text-white truncate">{actor.place_of_birth || (language === 'ku' ? 'نادیار' : 'Classified')}</p>
                                </div>
                                <div className="bg-white/5 p-4 rounded-2xl border border-white/5">
                                    <p className="text-[8px] font-black text-red-500 uppercase mb-1">{language === 'ku' ? 'ناوبانگ بۆ' : 'Known For'}</p>
                                    <p className="text-xs font-bold text-white">{actor.known_for_department}</p>
                                </div>
                            </div>
                            <div className="mb-10">
                                <h3 className="text-[10px] font-black uppercase text-gray-500 tracking-[0.2em] mb-4 flex items-center gap-2"><Info size={12}/> {language === 'ku' ? 'کورتەیەک' : 'Profile Summary'}</h3>
                                <p className="text-sm md:text-lg text-gray-300 leading-relaxed italic font-semibold">{actor.biography || (language === 'ku' ? "هیچ زانیاریەک بەردەست نیە" : "No bio found.")}</p>
                            </div>
                        </div>
                    </>
                )}
            </motion.div>
        </motion.div>
    );
};

const DetailPage: React.FC = () => {
  const { id } = useParams<{ id: string }>();
  const navigate = useNavigate();
  const { t, language } = useTranslation();
  const { addNotification } = useNotification();
  const [content, setContent] = useState<any>(null);
  const [loading, setLoading] = useState(true);
  const [isPlayerLoading, setIsPlayerLoading] = useState(true);
  const [cast, setCast] = useState<CastMember[]>([]);
  const [recommendations, setRecommendations] = useState<Content[]>([]);
  const [isInMyList, setIsInMyList] = useState(false);
  const [isPlayerModalOpen, setIsPlayerModalOpen] = useState(false);
  const [activeSource, setActiveSource] = useState('Vidking');
  const [showSourceSwitcher, setShowSourceSwitcher] = useState(false);
  const [selectedActorId, setSelectedActorId] = useState<number | null>(null);
  const [logoPath, setLogoPath] = useState<string | null>(null);
  const [trailerKey, setTrailerKey] = useState<string | null>(null);
  const [isTrailerModalOpen, setIsTrailerModalOpen] = useState(false);
  const [isMuted, setIsMuted] = useState(true);

  // Binge Setting
  const [bingeMode, setBingeMode] = useState(() => {
    try { return localStorage.getItem('flkrd_binge_mode') === 'true'; } catch(e) { return false; }
  });
  const [showBingePrompt, setShowBingePrompt] = useState(false);

  const sources = getRankedSources();

  const toggleBingeMode = () => {
    const newVal = !bingeMode;
    setBingeMode(newVal);
    try { localStorage.setItem('flkrd_binge_mode', String(newVal)); } catch(e) {}
  };

  const updateProgress = useCallback((time: number, duration: number) => {
    if (!content || !content.id) return;
    try {
        const progressData = localStorage.getItem('watchProgress');
        let progress: WatchProgress[] = progressData ? JSON.parse(progressData) : [];

        const index = progress.findIndex(i => i.id === content.id && i.type === 'movie');
        const item: WatchProgress = {
          id: content.id,
          type: 'movie',
          title: content.title,
          poster_path: content.poster_path,
          progress: time,
          duration: duration || content.runtime * 60 || 7200,
          lastWatched: Date.now()
        };

        if (index > -1) progress[index] = item;
        else progress.push(item);

        localStorage.setItem('watchProgress', JSON.stringify(progress));
        window.dispatchEvent(new Event('watchProgressUpdated'));

        if (time > (duration || 7200) * 0.98 && bingeMode && !showBingePrompt && recommendations.length > 0) {
            setShowBingePrompt(true);
        }
        window.dispatchEvent(new Event('storage'));
    } catch(e) {}
  }, [content, bingeMode, showBingePrompt, recommendations]);

  useEffect(() => {
    const handlePlayerMessages = (event: MessageEvent) => {
      try {
          let data = event.data;
          if (typeof data === 'string') {
              try { data = JSON.parse(data); } catch(e) { return; }
          }
          if (data && typeof data === 'object' && !Array.isArray(data)) {
            if (data.event === 'timeupdate' || data.event === 'pause') {
              updateProgress(data.time || data.currentTime || 0, data.duration || 0);
            }
          }
      } catch(e) {}
    };
    window.addEventListener('message', handlePlayerMessages);
    return () => window.removeEventListener('message', handlePlayerMessages);
  }, [updateProgress]);

  useEffect(() => {
    try {
        const myList = JSON.parse(localStorage.getItem('myList') || '[]');
        setIsInMyList(myList.some((item: any) => item.id === Number(id)));
    } catch(e) {}
  }, [id]);

  useEffect(() => {
    const fetchContentDetails = async () => {
        if (!id) return;
        setLoading(true);
        try {
            const apiLang = 'en-US';
            const endpoint = `/movie/${id}?api_key=${API_KEY}&language=${apiLang}&append_to_response=credits,similar,recommendations,images,videos&include_image_language=en,null`;
            const data = await fetchData(endpoint, language);
            if (data) {
                setContent(data);
                setCast(data.credits?.cast?.slice(0, 10) || []);
                let recs = [...(data.recommendations?.results || []), ...(data.similar?.results || [])];
                setRecommendations(recs.filter(r => r.id !== Number(id) && !isForbidden(r, language)));

                const logo = data.images?.logos?.find((l: any) => l.file_path && (l.iso_639_1 === 'en' || !l.iso_639_1));
                if (logo) setLogoPath(logo.file_path);

                const trailer = data.videos?.results?.find((v: any) => v.type === 'Trailer' && v.site === 'YouTube');
                if (trailer) setTrailerKey(trailer.key);
            }
        } catch (error) { console.error(error); } finally { setLoading(false); }
    };
    fetchContentDetails();
    window.scrollTo(0, 0);
  }, [id, language]);

  const handlePlayClick = () => {
    setIsPlayerLoading(true);
    setIsPlayerModalOpen(true);
  };

  const handleToggleMyList = () => {
    if (!content) return;
    try {
        let myList: MyListItem[] = JSON.parse(localStorage.getItem('myList') || '[]');
        const index = myList.findIndex(item => item.id === content.id);
        if (index > -1) {
          myList.splice(index, 1);
          setIsInMyList(false);
        } else {
          myList.push({ id: content.id, media_type: 'movie', title: content.title || '', poster_path: content.poster_path });
          setIsInMyList(true);
        }
        localStorage.setItem('myList', JSON.stringify(myList));
        window.dispatchEvent(new Event('storage'));
    } catch(e) {}
  };

  if (loading) return <div className="min-h-screen flex items-center justify-center bg-black"><Spinner /></div>;
  if (!content) return null;

  return (
    <div className="pb-40 bg-black min-h-screen text-white relative overflow-x-hidden transition-colors duration-300" dir={language === 'ku' ? 'rtl' : 'ltr'}>
        <div className="fixed inset-0 pointer-events-none z-0">
          <img src={`${IMAGE_BASE_URL}${content.backdrop_path}`} className="w-full h-full object-cover blur-[140px] opacity-20 scale-150" alt="" />
          <div className="absolute inset-0 bg-gradient-to-b from-black via-transparent to-black dark-gradient-mask"></div>
        </div>

        <AnimatePresence>
            {selectedActorId && <ActorModal actorId={selectedActorId} onClose={() => setSelectedActorId(null)} />}
        </AnimatePresence>

        <AnimatePresence>
            {isTrailerModalOpen && trailerKey && (
                <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }} className="fixed inset-0 bg-black/95 z-[300] backdrop-blur-3xl flex flex-col items-center justify-center p-4">
                    <div className="w-full max-w-5xl flex justify-between items-center mb-4">
                        <h2 className="text-xl font-black uppercase italic tracking-tighter">{t('playTrailer')}</h2>
                        <button onClick={() => setIsTrailerModalOpen(false)} className="p-3 bg-white/10 hover:bg-red-600 rounded-2xl transition-all"><X size={24}/></button>
                    </div>
                    <div className="w-full max-w-5xl aspect-video rounded-3xl overflow-hidden border border-white/10 shadow-2xl bg-black">
                        <iframe 
                            src={`https://www.youtube.com/embed/${trailerKey}?autoplay=1&rel=0`} 
                            className="w-full h-full" 
                            allowFullScreen 
                            allow="autoplay"
                        />
                    </div>
                </motion.div>
            )}
        </AnimatePresence>

        <AnimatePresence>
            {isPlayerModalOpen && (
                <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }} className="fixed inset-0 bg-black z-[200] flex flex-col items-center justify-center backdrop-blur-3xl" dir="ltr">
                    <div className="w-full max-w-7xl flex items-center justify-between p-4 md:p-6 bg-black/40 backdrop-blur-xl border-b border-white/5">
                        <button onClick={() => setIsPlayerModalOpen(false)} className="text-white bg-white/5 p-2.5 md:p-3 rounded-xl md:rounded-2xl hover:bg-red-600 transition-all shadow-xl group">
                          <X size={20} className="md:w-6 md:h-6 group-hover:rotate-90 transition-transform" />
                        </button>
                        <div className="flex flex-col items-center text-center">
                          <div className="flex items-center justify-center gap-2 mb-1">
                            <Shield size={12} className="text-green-500" />
                            <p className="text-[8px] md:text-[10px] font-black text-white uppercase tracking-[0.3em]">{language === 'ku' ? 'پەیوەندی پارێزراوە' : 'SECURE NODE ACTIVE'}</p>
                          </div>
                          <h2 className="text-xs md:sm font-bold uppercase tracking-tight italic line-clamp-1">{content.title}</h2>
                        </div>
                        <button onClick={() => setShowSourceSwitcher(!showSourceSwitcher)} className="flex items-center gap-2 px-3 md:px-4 py-2 rounded-xl bg-red-600/10 border border-red-500/20 text-red-500 text-[8px] md:text-[10px] font-black hover:bg-red-600 hover:text-white transition-all">
                           <RefreshCcw size={12} /> <span className="hidden sm:inline">RELINK</span>
                        </button>
                    </div>

                    <div className="w-full max-w-7xl aspect-video relative bg-black shadow-[0_0_100px_rgba(0,0,0,0.8)] border border-white/10 overflow-hidden">
                        {isPlayerLoading && <div className="absolute inset-0 flex flex-col items-center justify-center bg-black z-10"><Spinner /><span className="mt-6 text-[10px] font-black tracking-[0.5em] text-red-600 animate-pulse uppercase">Syncing Stream...</span></div>}

                        <AnimatePresence>
                            {showBingePrompt && recommendations.length > 0 && (
                                <motion.div initial={{ opacity: 0, y: 100 }} animate={{ opacity: 1, y: 0 }} exit={{ opacity: 0, y: 100 }} className="absolute bottom-10 left-10 right-10 z-50 bg-[#0c0c0c]/95 backdrop-blur-2xl border border-red-600/30 p-6 rounded-[2.5rem] flex flex-col md:flex-row items-center justify-between gap-6 shadow-2xl">
                                    <div className="flex items-center gap-5">
                                        <div className="w-20 h-28 rounded-2xl overflow-hidden shadow-xl border border-white/10 flex-shrink-0">
                                            <img src={`${IMAGE_BASE_URL_POSTER}${recommendations[0].poster_path}`} className="w-full h-full object-cover" alt="" />
                                        </div>
                                        <div>
                                            <div className="flex items-center gap-2 mb-2">
                                                <Activity size={12} className="text-red-600 animate-pulse" />
                                                <span className="text-[8px] font-black uppercase tracking-widest text-gray-500 italic">Auto-Sync Protocol</span>
                                            </div>
                                            <h4 className="text-xl font-[1000] text-white uppercase italic tracking-tighter mb-1 line-clamp-1">Up Next: {recommendations[0].title}</h4>
                                            <p className="text-[10px] text-gray-400 font-bold uppercase tracking-widest">Recommended follow-up node</p>
                                        </div>
                                    </div>
                                    <div className="flex gap-3">
                                        <button onClick={() => { setShowBingePrompt(false); navigate(`/details/movie/${recommendations[0].id}`); }} className="bg-red-600 text-white px-8 py-4 rounded-2xl font-black uppercase italic text-xs shadow-xl">Watch Now</button>
                                        <button onClick={() => setShowBingePrompt(false)} className="bg-white/5 text-white px-8 py-4 rounded-2xl font-black uppercase italic text-xs border border-white/10">Dismiss</button>
                                    </div>
                                </motion.div>
                            )}
                        </AnimatePresence>

                        <iframe 
                          src={getSourceUrl(activeSource, id!, 'movie')} 
                          allowFullScreen 
                          className="w-full h-full border-none pointer-events-auto" 
                          onLoad={() => setIsPlayerLoading(false)}
                        ></iframe>
                        <AnimatePresence>
                          {showSourceSwitcher && (
                            <motion.div initial={{ x: '100%' }} animate={{ x: 0 }} exit={{ x: '100%' }} className="absolute top-0 right-0 bottom-0 w-72 bg-black/95 backdrop-blur-3xl border-l border-white/10 z-30 p-6 overflow-y-auto scrollbar-hide">
                                <div className="flex items-center justify-between mb-8"><h3 className="text-base font-black uppercase italic tracking-tighter">Nodes</h3><button onClick={() => setShowSourceSwitcher(false)}><X size={20}/></button></div>
                                <div className="space-y-3 pb-10">
                                  {sources.map(s => (
                                    <button key={s.name} onClick={() => { setActiveSource(s.name); setIsPlayerLoading(true); setShowSourceSwitcher(false); }} className={`w-full p-4 rounded-2xl flex items-center justify-between transition-all border ${activeSource === s.name ? 'bg-red-600 border-red-500 text-white' : 'bg-white/5 border-white/5 hover:border-white/20 text-gray-400'}`}>
                                      <span className="text-[10px] font-black uppercase">{s.name}</span>
                                      {activeSource === s.name && <Zap size={14} fill="white" />}
                                    </button>
                                  ))}
                                </div>
                            </motion.div>
                          )}
                        </AnimatePresence>
                    </div>
                </motion.div>
            )}
        </AnimatePresence>

        <div className="relative w-full h-[75vh] md:h-[95vh] overflow-hidden z-10 group" dir="ltr">
            <div className="absolute inset-0 overflow-hidden">
                {trailerKey ? (
