import React, { useState, useEffect, useRef, useCallback } from 'react';
import { useNavigate } from 'react-router-dom';
import { motion, AnimatePresence } from 'framer-motion';
import { X, Plus, Check, Play, Trash2, AlertCircle, Loader2, Sparkles } from 'lucide-react';
import { Content, WatchProgress, MyListItem } from '../types';
import { fetchData } from '../services/tmdbService';
import { IMAGE_BASE_URL_POSTER } from '../constants';
import Spinner from './Spinner';
import { useTranslation } from '../contexts/LanguageContext';
import { useNotification } from '../contexts/NotificationContext';

interface RowProps {
  title: string;
  fetchUrl?: string;
  type?: 'movie' | 'tv';
  items?: (Content | WatchProgress | MyListItem)[];
  isProgressRow?: boolean;
}

const Row: React.FC<RowProps> = ({ title, fetchUrl, type, items, isProgressRow }) => {
  const [content, setContent] = useState<(Content | WatchProgress | MyListItem)[]>([]);
  const [loading, setLoading] = useState(true);
  const [loadingMore, setLoadingMore] = useState(false);
  const [hasError, setHasError] = useState(false);
  const [page, setPage] = useState(1);
  const [hasMore, setHasMore] = useState(true);
  const [myListIds, setMyListIds] = useState<Set<number>>(new Set());

  const navigate = useNavigate();
  const rowRef = useRef<HTMLDivElement>(null);
  const { language, t } = useTranslation();
  const { addNotification } = useNotification();

  const updateMyListIds = useCallback(() => {
    const myList = JSON.parse(localStorage.getItem('myList') || '[]');
    setMyListIds(new Set(myList.map((item: any) => item.id)));
  }, []);

  const getPagedUrl = (baseUrl: string, pageNum: number) => {
    const connector = baseUrl.includes('?') ? '&' : '?';
    return `${baseUrl}${connector}page=${pageNum}`;
  };

  const loadInitialData = async () => {
    updateMyListIds();
    setHasError(false);
    if (items) {
      setContent(items);
      setLoading(false);
      setHasMore(false);
    } else if (fetchUrl) {
      setLoading(true);
      const data = await fetchData(getPagedUrl(fetchUrl, 1), language);
      if (data && Array.isArray(data) && data.length > 0) {
        setContent(data);
        setPage(1);
        setHasMore(data.length >= 19); 
      } else if (data === null) {
        setHasError(true);
      } else {
        setContent([]);
        setHasMore(false);
      }
      setLoading(false);
    }
  };

  useEffect(() => {
    loadInitialData();
    window.addEventListener('storage', updateMyListIds);
    return () => window.removeEventListener('storage', updateMyListIds);
  }, [fetchUrl, items, language, updateMyListIds]);

  const handleToggleMyList = (e: React.MouseEvent, item: any, mediaType: 'movie' | 'tv') => {
    e.stopPropagation();
    let myList: MyListItem[] = JSON.parse(localStorage.getItem('myList') || '[]');
    const index = myList.findIndex(i => i.id === item.id);

    if (index > -1) {
      myList.splice(index, 1);
      addNotification({ type: 'info', title: t('notificationsInfoTitle'), message: t('myListRemoveSuccess') });
    } else {
      myList.push({ 
        id: item.id, 
        media_type: mediaType, 
        title: item.title || item.name || '', 
        poster_path: item.poster_path 
      });
      addNotification({ type: 'success', title: t('notificationsSuccessTitle'), message: t('myListAddSuccess') });
    }

    localStorage.setItem('myList', JSON.stringify(myList));
    updateMyListIds();
    window.dispatchEvent(new Event('storage'));
  };

  const handleRemoveProgress = (e: React.MouseEvent, id: number, mediaType: string) => {
      e.stopPropagation();
      const progress = JSON.parse(localStorage.getItem('watchProgress') || '[]');
      const filtered = progress.filter((item: any) => !(item.id === id && String(item.type) === mediaType));
      localStorage.setItem('watchProgress', JSON.stringify(filtered));
      setContent(prev => prev.filter(item => !(item.id === id && (item as any).type === mediaType)));
      window.dispatchEvent(new Event('storage'));
      window.dispatchEvent(new Event('watchProgressUpdated'));
  };

  const handleScroll = useCallback(async () => {
    if (rowRef.current && fetchUrl && hasMore && !loadingMore) {
        const { scrollLeft, scrollWidth, clientWidth } = rowRef.current;
        const isNearEnd = scrollWidth - scrollLeft - clientWidth < 600;

        if (isNearEnd) {
            setLoadingMore(true);
            const nextPage = page + 1;
            const data = await fetchData(getPagedUrl(fetchUrl, nextPage), language);
            if (data && Array.isArray(data) && data.length > 0) {
                setContent(prev => {
                    const existingIds = new Set(prev.map(i => i.id));
                    const uniqueNewItems = data.filter(i => !existingIds.has(i.id));
                    return [...prev, ...uniqueNewItems];
                });
                setPage(nextPage);
                if (data.length < 15) setHasMore(false);
            } else {
                setHasMore(false);
            }
            setLoadingMore(false);
        }
    }
  }, [fetchUrl, hasMore, loadingMore, page, language]);

  const navigateToDetail = (item: any) => {
    const mType = item.media_type || (item as WatchProgress).type || type;
    if (mType === 'dubbed') {
      navigate(`/dubbed-details/${item.id}`);
    } else {
      navigate(`/details/${mType}/${item.id}`);
    }
  };

  if (loading) return (
    <div className="mb-12 px-8">
        <div className="h-8 w-64 bg-white/5 rounded-full mb-8 animate-pulse" />
        <div className="flex gap-5 overflow-hidden">
            {[1,2,3,4,5,6].map(i => <div key={i} className="flex-shrink-0 w-32 md:w-56 aspect-[2/3] bg-white/5 rounded-[2rem] animate-pulse" />)}
        </div>
    </div>
  );

  if (hasError || !content || content.length === 0) return null;

  const isKurdish = language === 'ku';

  return (
    <div className="mb-10 md:mb-20 px-4 md:px-20 relative z-20 overflow-visible">
      {title && (
        <motion.div 
            initial={{ opacity: 0, x: -20 }}
            whileInView={{ opacity: 1, x: 0 }}
            viewport={{ once: true }}
            className="flex items-center justify-between mb-8"
        >
            <h2 className={`text-xl md:text-4xl font-[1000] flex items-center uppercase text-white ${!isKurdish ? 'italic tracking-tighter' : ''}`}>
                <motion.span 
                    animate={{ height: [24, 32, 24], opacity: [1, 0.5, 1] }}
                    transition={{ repeat: Infinity, duration: 2 }}
                    className="w-1 md:w-2 h-8 md:h-12 bg-red-600 rounded-full me-4 md:me-6 shadow-[0_0_15px_#e50914]"
                />
                <span className="shimmer-text">{title}</span>
            </h2>
            <div className="flex items-center gap-2 text-[10px] font-black text-gray-500 uppercase tracking-widest hidden md:flex">
                <Sparkles size={12} className="text-red-600 animate-pulse" />
                <span>Synchronized Archive</span>
            </div>
        </motion.div>
      )}

      <div className="relative group overflow-visible">
        <div 
          ref={rowRef} 
          onScroll={handleScroll} 
          className="flex overflow-x-scroll scrollbar-hide space-x-4 md:space-x-8 py-6 px-1 scroll-smooth overflow-visible"
        >
          {content.map((item, index) => {
              const mediaType = (item as Content).media_type || (item as WatchProgress).type || type;
              if (!item.poster_path || !mediaType) return null;
              const isAdded = myListIds.has(item.id);
              const hasProgress = 'progress' in item;
              const progressPct = hasProgress ? Math.min(100, ((item as WatchProgress).progress / ((item as WatchProgress).duration || 3600)) * 100) : 0;

              return (
              <motion.div
                key={`${item.id}-${index}-${mediaType}`}
                onClick={() => navigateToDetail(item)}
                className="flex-shrink-0 w-36 md:w-64 group/card relative cursor-pointer overflow-visible"
                whileTap={{ scale: 0.95 }}
                initial={{ opacity: 0, y: 30, scale: 0.9 }}
                whileInView={{ opacity: 1, y: 0, scale: 1 }}
                viewport={{ once: true }}
                transition={{ delay: (index % 6) * 0.05 }}
              >
                <div className="relative rounded-[2rem] md:rounded-[3rem] overflow-hidden border-2 border-white/5 shadow-2xl transition-all duration-500 group-hover/card:border-red-600 group-hover/card:shadow-[0_20px_50px_rgba(229,9,20,0.3)] bg-black">
                  <img
                    src={item.poster_path.startsWith('http') ? item.poster_path : `${IMAGE_BASE_URL_POSTER}${item.poster_path}`}
                    alt={(item as Content).title || (item as Content).name}
                    className="object-cover w-full h-full transition-transform duration-1000 md:group-hover/card:scale-110 md:group-hover/card:brightness-75"
                    loading="lazy"
                  />

                  <div className="absolute top-4 right-4 flex flex-col gap-2 z-30 opacity-0 group-hover/card:opacity-100 transition-all duration-300 translate-y-[-10px] group-hover/card:translate-y-0">
                      {!isProgressRow && (
                        <button
                          onClick={(e) => handleToggleMyList(e, item, mediaType as 'movie' | 'tv')}
                          className={`p-2.5 rounded-xl backdrop-blur-3xl border transition-all ${isAdded ? 'bg-red-600 border-red-500 text-white' : 'bg-black/60 border-white/10 text-white hover:bg-red-600'}`}
                        >
                          {isAdded ? <Check size={16} strokeWidth={4} /> : <Plus size={16} strokeWidth={4} />}
                        </button>
                      )}

                      {isProgressRow && (
                          <button
                              onClick={(e) => handleRemoveProgress(e, item.id, String(mediaType))}
                              className="p-2.5 bg-red-600/90 hover:bg-red-600 border border-red-500 rounded-xl text-white shadow-xl backdrop-blur-md transition-all active:scale-90"
                          >
                              <X size={16} strokeWidth={4} />
                          </button>
                      )}
                  </div>

                  {hasProgress && (
                      <div className="absolute bottom-0 left-0 right-0 h-2 bg-black/60 z-20 overflow-hidden">
                          <motion.div 
                            initial={{ width: 0 }}
                            animate={{ width: `${progressPct}%` }}
                            className="h-full bg-red-600 shadow-[0_0_15px_#e50914]" 
                          />
                      </div>
                  )}

                  <div className="absolute inset-0 bg-gradient-to-t from-black via-black/20 to-transparent opacity-0 md:group-hover/card:opacity-100 transition-all duration-500 flex flex-col justify-end p-6">
                      <div className="translate-y-6 group-hover/card:translate-y-0 transition-transform duration-500">
                          <h4 className="text-white text-sm md:text-lg font-black uppercase italic tracking-tighter truncate mb-4 drop-shadow-2xl">{(item as any).title || (item as any).name}</h4>
                          <div className="flex items-center gap-3">
                              <div className="bg-red-600 p-2.5 rounded-full shadow-[0_0_20px_rgba(229,9,20,0.6)]">
                                <Play size={14} fill="white" className="text-white ml-0.5" />
                              </div>
                              <span className="text-[10px] font-black uppercase tracking-[0.2em] text-white italic shimmer-text">{hasProgress ? 'Resume Node' : 'Initialize'}</span>
                          </div>
                      </div>
                  </div>
                </div>
              </motion.div>
            )}
          )}

          {hasMore && (
            <div className="flex-shrink-0 w-32 md:w-48 flex items-center justify-center p-8">
                {loadingMore ? (
                    <div className="flex flex-col items-center gap-4">
                        <Loader2 size={40} className="text-red-600 animate-spin" />
                        <span className="text-[9px] font-[1000] text-gray-500 uppercase tracking-[0.4em] text-center italic">Linking...</span>
                    </div>
                ) : (
                    <motion.div 
                        whileHover={{ scale: 1.2, x: 5 }}
                        className="w-1.5 h-20 bg-gradient-to-b from-transparent via-red-600/40 to-transparent rounded-full blur-[1px]" 
                    />
                )}
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

export default Row;

import React, { useState, useEffect, useCallback } from 'react';
import { useNavigate } from 'react-router-dom';
import { motion, AnimatePresence } from 'framer-motion';
// Added missing Calendar icon import
import { Star, Play, Info, ChevronLeft, ChevronRight, Zap, Sparkles, Calendar } from 'lucide-react';
import { Content } from '../types';
import { fetchData } from '../services/tmdbService';
import { requests, IMAGE_BASE_URL, API_KEY } from '../constants';
import { useTranslation } from '../contexts/LanguageContext';
import Spinner from './Spinner';

interface ExtendedContent extends Content {
  logo?: string;
}

const HeroBanner: React.FC = () => {
  const [items, setItems] = useState<ExtendedContent[]>([]);
  const [currentIndex, setCurrentIndex] = useState(0);
  const [loading, setLoading] = useState(true);
  const navigate = useNavigate();
  const { t, language } = useTranslation();
  const langCode = language === 'ku' ? 'ku' : 'en-US';

  const fetchHeroContent = useCallback(async () => {
    setLoading(true);
    const trendingData = await fetchData(requests.fetchTrending(langCode), language);
    if (trendingData && trendingData.length > 0) {
      const topItems = trendingData.slice(0, 5);

      const enrichedItems = await Promise.all(topItems.map(async (item: any) => {
        try {
          const type = item.media_type || 'movie';
          const res = await fetch(`https://api.themoviedb.org/3/${type}/${item.id}/images?api_key=${API_KEY}`);
          const imageData = await res.json();
          const logo = imageData.logos?.find((l: any) => l.iso_639_1 === 'en' || !l.iso_639_1)?.file_path;
          return { ...item, logo };
        } catch (e) {
          return item;
        }
      }));

      setItems(enrichedItems);
    }
    setLoading(false);
  }, [langCode, language]);

  useEffect(() => {
    fetchHeroContent();
  }, [fetchHeroContent]);

  useEffect(() => {
    if (items.length === 0 || loading) return;
    const interval = setInterval(() => {
      setCurrentIndex((prev) => (prev + 1) % items.length);
    }, 10000);
    return () => clearInterval(interval);
  }, [items, loading]);

  const handleNext = (e?: React.MouseEvent) => {
    e?.stopPropagation();
    setCurrentIndex((prev) => (prev + 1) % items.length);
  };

  const handlePrev = (e?: React.MouseEvent) => {
    e?.stopPropagation();
    setCurrentIndex((prev) => (prev - 1 + items.length) % items.length);
  };

  if (loading && items.length === 0) return <div className="h-[85vh] flex items-center justify-center bg-black"><Spinner /></div>;
  if (items.length === 0) return null;

  const currentItem = items[currentIndex];

  return (
    <div className="relative h-[85vh] md:h-screen w-full overflow-hidden bg-black group/hero">
      <AnimatePresence mode="wait">
        <motion.div
          key={`bg-${currentItem.id}`}
          initial={{ opacity: 0, scale: 1.15 }}
          animate={{ opacity: 1, scale: 1 }}
          exit={{ opacity: 0, scale: 1.1 }}
          transition={{ duration: 2, ease: "easeOut" }}
          className="absolute inset-0 z-0 overflow-hidden"
        >
          <img 
            src={`${IMAGE_BASE_URL}${currentItem.backdrop_path}`} 
            className="w-full h-full object-cover opacity-50 md:opacity-60 ken-burns" 
            alt="" 
          />
          <div className="absolute inset-0 bg-gradient-to-t from-black via-black/20 to-transparent" />
          <div className="absolute inset-0 bg-gradient-to-r from-black/60 via-transparent to-transparent hidden md:block" />
        </motion.div>
      </AnimatePresence>

      <div className={`absolute bottom-[20%] md:bottom-[28%] ${language === 'ku' ? 'right-6 md:right-32' : 'left-6 md:left-32'} z-30 flex flex-col items-start pointer-events-auto max-w-[90%] md:max-w-3xl`}>
        <AnimatePresence mode="wait">
          <motion.div
            key={`content-${currentItem.id}`}
            initial={{ opacity: 0, y: 40, filter: 'blur(10px)' }}
            animate={{ opacity: 1, y: 0, filter: 'blur(0px)' }}
            exit={{ opacity: 0, y: -20, filter: 'blur(10px)' }}
            transition={{ duration: 0.8, ease: [0.16, 1, 0.3, 1] }}
            className={`w-full flex flex-col ${language === 'ku' ? 'items-end' : 'items-start'}`}
          >
            {/* Badges */}
            <motion.div 
              initial={{ opacity: 0, x: -20 }}
              animate={{ opacity: 1, x: 0 }}
              transition={{ delay: 0.2 }}
              className={`flex items-center gap-3 mb-6 md:mb-8 ${language === 'ku' ? 'flex-row-reverse' : ''}`}
            >
                <div className="bg-red-600 text-white px-4 py-1.5 rounded-full text-[9px] md:text-[11px] font-black uppercase tracking-[0.3em] shadow-[0_0_20px_rgba(229,9,20,0.5)] flex items-center gap-2">
                   <Zap size={12} fill="white" className="animate-pulse" /> {t('trendingNow')}
                </div>
                <div className="bg-white/5 backdrop-blur-2xl px-4 py-1.5 rounded-full border border-white/10 text-gray-300 text-[9px] md:text-[11px] font-black uppercase tracking-[0.3em]">
                   {currentItem.media_type === 'tv' ? t('tvShows') : t('movies')}
                </div>
            </motion.div>

            {/* Title / Logo */}
            <div className="mb-8 md:mb-12 w-full">
              {currentItem.logo ? (
                <motion.img 
                  initial={{ opacity: 0, scale: 0.9, y: 20 }}
                  animate={{ opacity: 1, scale: 1, y: 0 }}
                  transition={{ delay: 0.4 }}
                  src={`${IMAGE_BASE_URL.replace('w1280', 'original')}${currentItem.logo}`} 
                  alt={currentItem.title || currentItem.name} 
                  className={`h-auto max-h-24 md:max-h-48 object-contain drop-shadow-[0_15px_30px_rgba(0,0,0,1)] ${language === 'ku' ? 'mr-auto' : 'ml-0'}`} 
                />
              ) : (
                <motion.h1 
                  initial={{ opacity: 0, x: -30 }}
                  animate={{ opacity: 1, x: 0 }}
                  transition={{ delay: 0.4 }}
                  className="text-4xl md:text-8xl font-[1000] uppercase italic tracking-tighter leading-[0.9] text-white drop-shadow-[0_10px_20px_rgba(0,0,0,1)] shimmer-text"
                >
                    {currentItem.title || currentItem.name}
                </motion.h1>
              )}
            </div>

            {/* Overview / Synopsis - NEW ADDITION for premium feel */}
            <motion.p 
              initial={{ opacity: 0 }}
              animate={{ opacity: 0.8 }}
              transition={{ delay: 0.6 }}
              className={`text-gray-300 font-bold italic text-sm md:text-xl line-clamp-2 mb-10 max-w-2xl ${language === 'ku' ? 'text-right' : 'text-left'}`}
            >
              {currentItem.overview}
            </motion.p>

            {/* Meta Info */}
            <motion.div 
              initial={{ opacity: 0, y: 20 }}
              animate={{ opacity: 1, y: 0 }}
              transition={{ delay: 0.7 }}
              className={`flex items-center gap-6 mb-10 md:mb-14 ${language === 'ku' ? 'flex-row-reverse' : ''}`}
            >
                <div className="flex items-center gap-2">
                    <Calendar size={14} className="text-red-600" />
                    <span className="text-xs md:text-lg font-black uppercase tracking-[0.2em] text-gray-400 italic">
                       {currentItem.release_date?.split('-')[0] || currentItem.first_air_date?.split('-')[0]}
                    </span>
