const NeuralCoreInsight: React.FC<{ title: string, language: string }> = ({ title, language }) => {
    const [insight, setInsight] = useState<string | null>(null);
    const [loading, setLoading] = useState(false);
    const [isOpen, setIsOpen] = useState(false);
    const { t } = useTranslation();

    const generateInsight = async () => {
        if (insight || loading) {
            setIsOpen(true);
            return;
        }
        setLoading(true);
        setIsOpen(true);
        try {
            const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
            const prompt = language === 'ku' 
                ? `تۆ ناوەندی دەماری فڵکردی (FLKRD Neural Core). بە زمانێکی کوردی زۆر پاراو و مرۆیی (تێکەڵەی سۆرانی و بادینی بە ئەلفبێی عەرەبی) کورتەیەک یان زانیارییەکی سەرنجڕاکێش دەربارەی فیلمی "${title}" بدە. وا بکە هەست بکات کە سیستمێکی ژیری دەستکردی هاوڕێیانەیە قسە دەکات. وەڵامەکە کورت بێت.`
                : `You are the FLKRD Neural Core. Provide a warm, human-like, and high-tech insight or trivia about the movie "${title}". Sound like a sophisticated cinematic AI companion. Keep it concise.`;

            const response = await ai.models.generateContent({
                model: 'gemini-3-flash-preview',
                contents: prompt,
                config: {
                    systemInstruction: "You are the FLKRD Neural Core, a high-fidelity cinematic AI. You speak with human warmth and technical precision. You are an expert in cinema and linguistics.",
                    temperature: 0.8,
                    // Fix: Set both maxOutputTokens and thinkingConfig.thinkingBudget at the same time for Gemini 3 models.
                    maxOutputTokens: 250,
                    thinkingConfig: { thinkingBudget: 100 },
                }
            });
            setInsight(response.text || "Neural connection timed out.");
        } catch (e) {
            setInsight("Neural link unstable. Please try again.");
        } finally {
            setLoading(false);
        }
    };

    return (
        <div className="relative z-50">
            <motion.button 
                whileHover={{ scale: 1.1 }}
                whileTap={{ scale: 0.9 }}
                onClick={generateInsight}
                className="group relative flex items-center gap-3 bg-red-600/10 hover:bg-red-600/20 border border-red-600/30 p-4 rounded-full transition-all shadow-[0_0_20px_rgba(229,9,20,0.2)]"
            >
                <motion.div 
                    animate={{ rotate: 360 }}
                    transition={{ repeat: Infinity, duration: 10, ease: "linear" }}
                    className="absolute inset-0 rounded-full border border-dashed border-red-600/40"
                />
                <BrainCircuit className="text-red-500 group-hover:text-red-400" size={24} />
                <span className="text-[10px] font-black uppercase tracking-[0.3em] text-red-500 hidden md:block">{t('neuralInsight')}</span>
            </motion.button>

            <AnimatePresence>
                {isOpen && (
                    <motion.div 
                        initial={{ opacity: 0, y: 20, scale: 0.9 }}
                        animate={{ opacity: 1, y: 0, scale: 1 }}
                        exit={{ opacity: 0, y: 20, scale: 0.9 }}
                        className="fixed md:absolute bottom-24 right-0 md:bottom-20 md:right-0 w-[90vw] md:w-96 bg-[#0c0c0c]/90 backdrop-blur-3xl border border-white/10 rounded-[2.5rem] p-8 shadow-[0_50px_100px_rgba(0,0,0,1)] z-[100]"
                    >
                        <div className="absolute top-0 left-0 w-full h-1 bg-red-600" />
                        <button onClick={() => setIsOpen(false)} className="absolute top-6 right-6 text-gray-500 hover:text-white"><X size={20}/></button>

                        <div className="flex items-center gap-3 mb-6">
                            <Cpu size={16} className="text-red-600 animate-pulse" />
                            <h4 className="text-xs font-[1000] uppercase tracking-[0.4em] text-white italic">{t('askCore')}</h4>
                        </div>

                        {loading ? (
                            <div className="py-10 flex flex-col items-center gap-4">
                                <Spinner size="sm" />
                                <span className="text-[10px] font-black uppercase tracking-widest text-gray-500 animate-pulse">{t('thinking')}</span>
                            </div>
                        ) : (
                            <motion.p 
                                initial={{ opacity: 0 }}
                                animate={{ opacity: 1 }}
                                className="text-sm md:text-base text-gray-200 leading-relaxed italic font-semibold text-right"
                                dir={language === 'ku' ? 'rtl' : 'ltr'}
                            >
                                {insight}
                            </motion.p>
                        )}
                        <div className="mt-8 flex justify-center">
                            <div className="h-0.5 w-12 bg-white/10 rounded-full" />
                        </div>
                    </motion.div>
                )}
            </AnimatePresence>
        </div>
    );
};

