    document.documentElement.style.setProperty('--brand-red', activeColor);
    localStorage.setItem('flkrd_accent_color', activeColor);
  }, [activeColor]);

  const handleNotificationRequest = async () => {
    if (!('Notification' in window)) {
        addNotification({ type: 'error', title: t('notificationsErrorTitle'), message: t('notificationsNotSupported') });
        return;
    }
