const NeuralCoreInsight: React.FC<{ title: string, language: string }> = ({ title, language }) => {
    const [insight, setInsight] = useState<string | null>(null);
    const [loading, setLoading] = useState(false);
    const [isOpen, setIsOpen] = useState(false);
    const { t } = useTranslation();
    const { accentColor } = useUI();

    const generateInsight = async () => {
        if (insight || loading) {
            setIsOpen(true);
            return;
        }
        setLoading(true);
        setIsOpen(true);
        try {
            const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
            const prompt = language === 'ku' 
                ? `تۆ ناوەندی دەماری فڵکردی (FLKRD Neural Core). بە زمانێکی کوردی زۆر پاراو و مرۆیی (تێکەڵەی سۆرانی و بادینی بە ئەلفبێی عەرەبی) کورتەیەک یان زانیارییەکی سەرنجڕاکێش دەربارەی فیلمی "${title}" بدە. وا بکە هەست بکات کە سیستمێکی ژیری دەستکردی هاوڕێیانەیە قسە دەکات. وەڵامەکە کورت بێت.`
                : `You are the FLKRD Neural Core. Provide a warm, human-like, and high-tech insight or trivia about the movie "${title}". Sound like a sophisticated cinematic AI companion. Keep it concise.`;

            const response = await ai.models.generateContent({
                model: 'gemini-3-flash-preview',
                contents: prompt,
                config: {
                    systemInstruction: "You are the FLKRD Neural Core, a high-fidelity cinematic AI. You speak with human warmth and technical precision. You are an expert in cinema and linguistics.",
                    temperature: 0.8,
                    maxOutputTokens: 250,
                    thinkingConfig: { thinkingBudget: 100 },
                }
            });
            setInsight(response.text || "Neural connection timed out.");
        } catch (e) {
            setInsight("Neural link unstable. Please try again.");
        } finally {
            setLoading(false);
        }
    };

    return (
        <div className="relative z-50">
            <motion.button 
                whileHover={{ scale: 1.1 }}
                whileTap={{ scale: 0.9 }}
                onClick={generateInsight}
                className="group relative flex items-center gap-3 bg-white/5 hover:bg-white/10 backdrop-blur-xl border border-white/10 p-4 rounded-full transition-all shadow-xl"
                style={{ borderColor: isOpen ? accentColor : 'rgba(255,255,255,0.1)' }}
            >
                <motion.div 
                    animate={{ rotate: 360 }}
                    transition={{ repeat: Infinity, duration: 10, ease: "linear" }}
                    className="absolute inset-0 rounded-full border border-dashed"
                    style={{ borderColor: accentColor + '66' }}
                />
                <BrainCircuit style={{ color: accentColor }} size={24} />
                <span className="text-[10px] font-black uppercase tracking-[0.3em] hidden md:block" style={{ color: accentColor }}>{t('neuralInsight')}</span>
            </motion.button>

            <AnimatePresence>
                {isOpen && (
                    <motion.div 
                        initial={{ opacity: 0, y: 20, scale: 0.9 }}
                        animate={{ opacity: 1, y: 0, scale: 1 }}
                        exit={{ opacity: 0, y: 20, scale: 0.9 }}
                        className="fixed md:absolute bottom-24 right-0 md:bottom-20 md:right-0 w-[90vw] md:w-96 bg-[var(--card-bg)] backdrop-blur-3xl border border-white/10 rounded-[2.5rem] p-8 shadow-[0_50px_100px_rgba(0,0,0,0.8)] z-[100]"
                    >
                        <div className="absolute top-0 left-0 w-full h-1" style={{ backgroundColor: accentColor }} />
                        <button onClick={() => setIsOpen(false)} className="absolute top-6 right-6 text-[var(--text-secondary)] hover:text-[var(--text-primary)]"><X size={20}/></button>

                        <div className="flex items-center gap-3 mb-6">
                            <Cpu size={16} className="animate-pulse" style={{ color: accentColor }} />
                            <h4 className="text-xs font-[1000] uppercase tracking-[0.4em] text-[var(--text-primary)] italic">{t('askCore')}</h4>
                        </div>

                        {loading ? (
                            <div className="py-10 flex flex-col items-center gap-4">
                                <Spinner size="sm" />
                                <span className="text-[10px] font-black uppercase tracking-widest text-[var(--text-secondary)] animate-pulse">{t('thinking')}</span>
                            </div>
                        ) : (
                            <motion.p 
                                initial={{ opacity: 0 }}
                                animate={{ opacity: 1 }}
                                className="text-sm md:text-base text-[var(--text-primary)] leading-relaxed italic font-semibold"
                                dir={language === 'ku' ? 'rtl' : 'ltr'}
                            >
                                {insight}
                            </motion.p>
                        )}
                    </motion.div>
                )}
            </AnimatePresence>
        </div>
    );
};

