import { useUI } from '../contexts/UIContext';
import { useNotification } from '../contexts/NotificationContext';

const ShareBtn: React.FC<{ icon: React.ReactNode, label: string, onClick: () => void, color: string, text?: string }> = ({ icon, label, onClick, color, text = "text-white" }) => (
    <button onClick={onClick} className={`flex flex-col items-center justify-center p-6 rounded-3xl transition-all hover:scale-105 active:scale-95 ${color} ${text} shadow-xl`}>
