const DubbedMoviesPage: React.FC = () => {
    const [dubbedContent, setDubbedContent] = useState<Content[]>([]);
    const [loading, setLoading] = useState(true);
    const [filterTrailers, setFilterTrailers] = useState(false);
    const [shareTarget, setShareTarget] = useState<any>(null);

    const navigate = useNavigate();
    const { t, language } = useTranslation();
    const { theme } = useUI();
    const { addNotification } = useNotification();
    const langCode = language === 'ku' ? 'ku' : 'en-US';

    useEffect(() => {
        const loadDubbedArchive = async () => {
            setLoading(true);
            const enriched = await Promise.all(CUSTOM_DUBBED_ARCHIVE.map(async (movie) => {
                const endpoint = `/movie/${movie.id}?api_key=${API_KEY}&language=${langCode}&append_to_response=videos`;
                const realData = await fetchData(endpoint, language);
                return {
                    ...(realData || {}),
                    ...movie,
                    media_type: 'movie'
                } as any;
            }));
            setDubbedContent(enriched);
            setLoading(false);
        };
        loadDubbedArchive();
    }, [langCode, language]);

    const filteredContent = useMemo(() => {
        if (!filterTrailers) return dubbedContent;
        return dubbedContent.filter(item => item.videos?.results && item.videos.results.length > 0);
    }, [dubbedContent, filterTrailers]);

    const handlePlay = (item: any) => {
        navigate(`/dubbed-details/${item.id}`, { 
            state: { 
                customSource: item.customStream,
                isDubbedMode: true,
                customData: item 
            } 
        });
    };

