              className={`bg-black/25 dark-mode-box backdrop-blur-xl border border-white/10 rounded-full w-9 h-9 md:w-12 md:h-12 flex items-center justify-center transition-all shadow-lg group ${isHistoryOpen ? 'bg-brand' : 'hover:bg-brand/20'}`}
              aria-label="Recently Viewed"
            >
              <History className={`w-5 h-5 md:w-6 md:h-6 transition-colors ${isHistoryOpen ? 'text-white' : 'text-[var(--text-secondary)] group-hover:text-brand'}`} />
            </button>

            <AnimatePresence>
              {isHistoryOpen && (
                <motion.div
                  initial={{ opacity: 0, y: 15, scale: 0.95 }}
                  animate={{ opacity: 1, y: 0, scale: 1 }}
                  exit={{ opacity: 0, y: 15, scale: 0.95 }}
                  className="absolute right-0 mt-4 w-72 md:w-96 bg-card-bg border border-border-color rounded-[2rem] md:rounded-[2.5rem] shadow-[0_50px_100px_rgba(0,0,0,0.8)] overflow-hidden z-50 backdrop-blur-3xl"
                >
                  <div className="p-5 border-b border-white/5 flex items-center justify-between">
                    <div className="flex items-center gap-2">
                       <History className="w-3.5 h-3.5 md:w-4 md:h-4 text-brand" />
                       <span className="text-[10px] font-[1000] uppercase tracking-[0.3em] text-sec-text italic">{t('recentlyViewed')}</span>
                    </div>
                    <button onClick={() => setIsHistoryOpen(false)} className="text-gray-600 hover:text-white transition-colors"><X className="w-4 h-4" /></button>
                  </div>

                  <div className="max-h-[400px] overflow-y-auto scrollbar-hide py-2">
                    {recentItems.length > 0 ? (
                      recentItems.map((item) => {
                        const progressPct = Math.min(100, (item.progress / (item.duration || 1)) * 100);
                        return (
                          <button
                            key={`${item.id}-${item.type}`}
