    if (player) {
      // Listen for the 'ready' event to ensure the script has fully initialized the custom element.
      player.addEventListener('ready', syncLottieState);
      // Attempt an immediate sync in case it's already ready (upgraded)
      syncLottieState();
    }

    return () => {
      if (player) player.removeEventListener('ready', syncLottieState);
    };
  }, [theme]);

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (historyRef.current && !historyRef.current.contains(event.target as Node)) {
        setIsHistoryOpen(false);
      }
    };
    if (isHistoryOpen) {
      document.addEventListener('mousedown', handleClickOutside);
    }
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, [isHistoryOpen]);

