import { WatchProgress } from '../types';
import { IMAGE_BASE_URL_POSTER } from '../constants';

// Fix: Define dotlottie-wc as a variable to resolve JSX errors
const DotLottieWC = 'dotlottie-wc' as any;

const Header: React.FC<{ scrolled: boolean }> = () => {
  const [isSettingsOpen, setIsSettingsOpen] = useState(false);
  const [isHistoryOpen, setIsHistoryOpen] = useState(false);
  const [recentItems, setRecentItems] = useState<WatchProgress[]>([]);
  const historyRef = useRef<HTMLDivElement>(null);
  const lottieRef = useRef<any>(null);

  const { theme, toggleTheme, accentColor, scale } = useUI();
  const { t } = useTranslation();
  const navigate = useNavigate();

  useEffect(() => {
    const loadHistory = () => {
      try {
        const data = localStorage.getItem('watchProgress');
        if (data) {
          const progress: WatchProgress[] = JSON.parse(data);
          const sorted = progress
            .sort((a, b) => (b.lastWatched || 0) - (a.lastWatched || 0))
            .slice(0, 5);
          setRecentItems(sorted);
        }
      } catch (e) {
        console.error("History Load Error", e);
      }
    };

    loadHistory();
    window.addEventListener('storage', loadHistory);
    window.addEventListener('watchProgressUpdated', loadHistory);
    return () => {
      window.removeEventListener('storage', loadHistory);
      window.removeEventListener('watchProgressUpdated', loadHistory);
    };
  }, []);

  // Robust synchronization for the DotLottie State Machine
  useEffect(() => {
    const player = lottieRef.current;
    if (!player) return;

    let retryInterval: number;

    const syncTheme = () => {
      if (player.dotLottie) {
        try {
          const isDark = theme === 'dark';
          // Using setStateMachineInput is the standard for .lottie bundles with Logic
          player.dotLottie.setStateMachineInput('StateMachine1', 'theme', isDark);
          player.dotLottie.setStateMachineInput('StateMachine1', 'dark', isDark);
          player.dotLottie.setStateMachineInput('StateMachine1', 'switch', isDark);

          if (retryInterval) clearInterval(retryInterval);
        } catch (err) {
          // Engine might still be initializing, retry happens via interval
        }
      }
    };

    // Listen for the official ready event
    player.addEventListener('ready', syncTheme);

    // Polling fallback to handle race conditions where 'ready' fires before the instance is exposed to React ref
    retryInterval = window.setInterval(syncTheme, 100);

    // Initial check
    syncTheme();

    return () => {
      player.removeEventListener('ready', syncTheme);
      clearInterval(retryInterval);
    };
  }, [theme]);

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (historyRef.current && !historyRef.current.contains(event.target as Node)) {
        setIsHistoryOpen(false);
      }
    };
    if (isHistoryOpen) {
      document.addEventListener('mousedown', handleClickOutside);
    }
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, [isHistoryOpen]);

  const handleResume = (item: WatchProgress) => {
    setIsHistoryOpen(false);
    if (String(item.type) === 'dubbed') {
      navigate(`/dubbed-details/${item.id}`);
    } else {
      navigate(`/details/${item.type}/${item.id}`);
    }
  };

  return (
    <>
      <header className={`fixed top-0 left-0 right-0 z-40 p-3 sm:p-6 lg:p-8 flex items-center justify-between pointer-events-none transition-all duration-500`}>
        <Link to="/" className="pointer-events-auto">
          <div className="flex items-center gap-2 bg-black/25 dark-mode-box backdrop-blur-xl border border-white/10 rounded-xl p-1.5 md:p-2 transition-all shadow-lg">
            <img src="https://i.imgur.com/DF1UZL3.png" alt="FLKRD LOGO" className="h-6 md:h-10 object-contain" />
            <h1 className="text-sm md:text-2xl font-bold text-[var(--brand-red)] tracking-wider pr-2 hidden md:block">FLKRD MOVIES</h1>
          </div>
        </Link>
        <div className="flex items-center space-x-2 md:space-x-3 pointer-events-auto">
          <button
            onClick={() => navigate('/continue-watching')}
            className="hidden lg:flex items-center gap-2 bg-[var(--brand-red)] hover:brightness-110 text-white px-4 py-2.5 rounded-2xl font-black text-[10px] uppercase tracking-widest shadow-xl transition-all hover:scale-105"
            aria-label={t('continueWatching')}
          >
            <PlayCircle className="w-4 h-4 md:w-5 md:h-5 text-[var(--brand-red)]" fill="white" />
            <span className="italic">{t('continueWatching')}</span>
          </button>

          <div className="relative" ref={historyRef}>
            <button
              onClick={() => setIsHistoryOpen(!isHistoryOpen)}
              className={`bg-black/25 dark-mode-box backdrop-blur-xl border border-white/10 rounded-full w-9 h-9 md:w-12 md:h-12 flex items-center justify-center transition-all shadow-lg group ${isHistoryOpen ? 'bg-brand' : 'hover:bg-brand/20'}`}
              aria-label="Recently Viewed"
            >
              <History className={`w-5 h-5 md:w-6 md:h-6 transition-colors ${isHistoryOpen ? 'text-white' : 'text-[var(--text-secondary)] group-hover:text-brand'}`} />
            </button>

