                                <span className="text-[8px] font-black uppercase text-brand">{Math.floor(progressPct)}%</span>
                              </div>
                              <div className="mt-2 w-full h-1 bg-white/5 rounded-full overflow-hidden">
                                <motion.div 
                                  initial={{ width: 0 }}
                                  animate={{ width: `${progressPct}%` }}
                                  className="h-full bg-brand" 
                                />
                              </div>
                            </div>
                            <ChevronRight className="w-3.5 h-3.5 text-gray-700 group-hover:text-brand group-hover:translate-x-1 transition-all" />
                          </button>
                        );
                      })
                    ) : (
                      <div className="p-12 text-center flex flex-col items-center gap-4">
                        <History className="w-10 h-10 text-gray-800" />
                        <p className="text-[10px] font-black uppercase tracking-widest text-gray-500">Your archive is empty.</p>
                      </div>
                    )}
                  </div>

                  {recentItems.length > 0 && (
                    <button 
                      onClick={() => { setIsHistoryOpen(false); navigate('/continue-watching'); }}
                      className="w-full p-4 bg-white/5 border-t border-white/5 text-[9px] font-black uppercase tracking-[0.4em] text-gray-400 hover:text-white hover:bg-brand/10 transition-all flex items-center justify-center gap-2"
                    >
                      {t('seeMore')} Archive <ChevronRight className="w-2.5 h-2.5" />
                    </button>
                  )}
                </motion.div>
              )}
            </AnimatePresence>
          </div>

          {/* Bigger Theme Toggle without background for cleaner animation appearance */}
          <button
            onClick={toggleTheme}
            className="w-14 h-14 md:w-20 md:h-20 flex items-center justify-center transition-all overflow-hidden group relative active:scale-90"
            aria-label="Toggle Theme"
          >
            <div className="w-full h-full pointer-events-none transform scale-[2.2] md:scale-[2.8] flex items-center justify-center relative">
              {/* Invisible fallback icons to maintain accessibility and layout structure */}
              <div className="absolute inset-0 flex items-center justify-center opacity-0 pointer-events-none">
                 {theme === 'dark' ? <Moon className="w-4 h-4" /> : <Sun className="w-4 h-4" />}
              </div>

              <DotLottieWC
                ref={lottieRef}
                src="https://lottie.host/ce94f674-0a01-4172-8d74-09c0589a4a65/iqqsn5HFah.lottie"
                active-animation-id="theme"
                state-machine-id="StateMachine1"
                autoplay
                background="transparent"
                style={{ width: '100%', height: '100%', display: 'block', position: 'relative', zIndex: 1 }}
