        try {
          const isDark = theme === 'dark';
          // This specific Lottie switcher usually uses 'Boolean' or 'switch' as the input ID
          // We set all possible common IDs to ensure the transition animates
          player.dotLottie.setStateMachineInput('StateMachine1', 'Boolean', isDark);
          player.dotLottie.setStateMachineInput('StateMachine1', 'switch', isDark);
          player.dotLottie.setStateMachineInput('StateMachine1', 'dark', isDark);
          player.dotLottie.setStateMachineInput('StateMachine1', 'theme', isDark);

          // Clear interval if successful to save resources
          if (player.dotLottie.isLoaded) {
             // We keep polling slightly longer to ensure the first transition is smooth
             setTimeout(() => { if (retryInterval) clearInterval(retryInterval); }, 1000);
          }
        } catch (err) {
          // Engine warming up...
        }
      }
    };

    // Events for initial lifecycle
    player.addEventListener('ready', syncTheme);
    player.addEventListener('load', syncTheme);

    // Polling fallback because the 'ready' event can fire before React refs are fully mapped
    retryInterval = window.setInterval(syncTheme, 200);
    syncTheme();

    return () => {
      player.removeEventListener('ready', syncTheme);
      player.removeEventListener('load', syncTheme);
      clearInterval(retryInterval);
    };
  }, [theme]);

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (historyRef.current && !historyRef.current.contains(event.target as Node)) {
        setIsHistoryOpen(false);
      }
    };
    if (isHistoryOpen) {
      document.addEventListener('mousedown', handleClickOutside);
    }
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, [isHistoryOpen]);

  const handleResume = (item: WatchProgress) => {
    setIsHistoryOpen(false);
    if (String(item.type) === 'dubbed') {
      navigate(`/dubbed-details/${item.id}`);
