            VStack(spacing: 0) {
                if viewModel.activeCategory == nil {
                    // SELECTION SCREEN
                    CategorySelectionGrid(viewModel: viewModel, namespace: animation)
                } else if viewModel.activeCategory == .country && viewModel.selectedCountry == nil {
                    // COUNTRY PICKER
                    CountryPickerGrid(viewModel: viewModel)
                } else {
                    // MOVIE GRID & FILTER HEADER
                    StickyFilterHeader(viewModel: viewModel)

                    ScrollView {
                        LazyVGrid(columns: [GridItem(.adaptive(minimum: 110), spacing: 15)], spacing: 20) {
                            ForEach(viewModel.movies) { movie in
                                MovieCard(movie: movie)
