### 1. The Search Logic (ViewModel)
This handles the neural filtering and TMDB API integration using modern Swift Concurrency.

```swift
import SwiftUI
import Observation

@Observable
class SearchViewModel {
    var query: String = ""
    var results: [Movie] = []
    var isSearching: Bool = false
    var isBlocked: Bool = false

    // Neural Protection Keywords
    private let forbidden = ["porn", "xxx", "sex", "explicit", "nude"]
    private let apiKey = "39ad6c4210f7e4357f3b5762fcaeb1db"

    func performSearch() async {
        let trimmed = query.lowercased().trimmingCharacters(in: .whitespaces)

        // Safety Protocol
        if forbidden.contains(where: { trimmed.contains($0) }) {
            self.isBlocked = true
            self.results = []
            return
        }

        guard trimmed.count > 1 else { 
            self.results = []
            return 
        }

        self.isBlocked = false
        self.isSearching = true

        let urlString = "https://api.themoviedb.org/3/search/multi?api_key=\(apiKey)&query=\(query.addingPercentEncoding(withAllowedCharacters: .urlQueryAllowed) ?? "")&include_adult=false"

        do {
            let (data, _) = try await URLSession.shared.data(from: URL(string: urlString)!)
            let response = try JSONDecoder().decode(TMDBResponse.self, from: data)
            // Filter only movies and tv with posters
            self.results = response.results.filter { $0.poster_path != nil && ($0.media_type == "movie" || $0.media_type == "tv") }
        } catch {
            print("Neural Link Failure")
        }

        self.isSearching = false
    }
}
```

### 2. The Futuristic UI (Main Search View)
This view uses **Mesh Gradients** and **Spatial Glassmorphism** to achieve the iOS 26 look.

