@Model
class WatchProgress {
    @Attribute(.unique) var id: String
    var title: String
    var posterPath: String
    var progress: Double // In seconds
    var duration: Double // In seconds
    var lastWatched: Date
    var mediaType: String // "movie", "tv", or "dubbed"
    var season: Int?
    var episode: Int?

