This handles persistence using `@AppStorage` and generates the sharing sequences.

```swift
import SwiftUI
import Observation

struct ArchiveItem: Identifiable, Codable, Equatable {
    let id: Int
    let title: String
    let posterPath: String
    let mediaType: String // "movie" or "tv"
}

@Observable
class ArchiveViewModel {
    var items: [ArchiveItem] = []
    var showShareSheet = false
    var shareURL: String = ""

    private let storageKey = "flkrd_my_list"

    init() {
        loadArchive()
    }

    func loadArchive() {
        if let data = UserDefaults.standard.data(forKey: storageKey),
           let decoded = try? JSONDecoder().decode([ArchiveItem].self, from: data) {
            self.items = decoded
        }
    }

    func removeItem(id: Int) {
        withAnimation(.spring(response: 0.4, dampingFraction: 0.8)) {
            items.removeAll { $0.id == id }
            saveArchive()
        }
        UIImpactFeedbackGenerator(style: .medium).impactOccurred()
    }

    func clearAll() {
        withAnimation {
            items = []
            saveArchive()
        }
        UIImpactFeedbackGenerator(style: .heavy).impactOccurred()
    }

    private func saveArchive() {
        if let encoded = try? JSONEncoder().encode(items) {
            UserDefaults.standard.set(encoded, forKey: storageKey)
        }
    }

    func generateShareProtocol() {
        guard let data = try? JSONEncoder().encode(items) else { return }
        let base64 = data.base64EncodedString()
        self.shareURL = "flkrd://archive?sync=\(base64)"
        self.showShareSheet = true
    }
}
```

