### 1. The Home Logic (ViewModel)
Handles the neural synchronization with TMDB and manages different content sectors.

```swift
import SwiftUI
import Observation

@Observable
class HomeViewModel {
    var heroMovie: Movie?
    var trendingNow: [Movie] = []
    var flkrdOriginals: [Movie] = []
    var actionNodes: [Movie] = []
    var watchHistory: [WatchProgress] = []
    var isLoading = true

    private let apiKey = "39ad6c4210f7e4357f3b5762fcaeb1db"

    func syncNeuralLink() async {
        isLoading = true

        async let trending = fetchNodes(path: "trending/all/week")
        async let originals = fetchNodes(path: "discover/tv", extra: "&with_networks=213")
        async let action = fetchNodes(path: "discover/movie", extra: "&with_genres=28")

        let (t, o, a) = await (trending, originals, action)

        self.trendingNow = t
        self.flkrdOriginals = o
        self.actionNodes = a
        self.heroMovie = t.first

        // Mocking Watch History for UI demonstration
        self.watchHistory = [
            WatchProgress(id: "1", title: "NE ZHA 2", posterPath: "https://i.imgur.com/4HoT8Yf.png", progress: 4500, duration: 7200, mediaType: "movie")
        ]

        withAnimation(.spring(response: 0.8, dampingFraction: 0.8)) {
            self.isLoading = false
        }
    }

    private func fetchNodes(path: String, extra: String = "") async -> [Movie] {
        let url = URL(string: "https://api.themoviedb.org/3/\(path)?api_key=\(apiKey)&language=en-US\(extra)")!
        do {
            let (data, _) = try await URLSession.shared.data(from: url)
            let decoded = try JSONDecoder().decode(TMDBResponse.self, from: data)
            return decoded.results
        } catch { return [] }
    }
}
