                        HomeContentRow(title: "FLKRD ORIGINALS", items: viewModel.flkrdOriginals)
                        HomeContentRow(title: "ACTION NODES", items: viewModel.actionNodes)
                    }
                    .padding(.top, 30)
                    .padding(.bottom, 120)
                }
                .background(GeometryReader { geo in
                    Color.clear.onAppear { }
                        .onChange(of: geo.frame(in: .global).minY) { _, newValue in
                            scrollOffset = -newValue
                        }
                })
            }

            // 4. Futuristic Sticky Header
            HomeHeader(offset: scrollOffset)
        }
        .task { await viewModel.syncNeuralLink() }
    }
}
```

### 3. Visual Components

#### A. Cinematic Hero (Wide-Scale Integration)
```swift
struct HomeHeroSection: View {
    let movie: Movie

    var body: some View {
        ZStack(alignment: .bottomLeading) {
            AsyncImage(url: URL(string: "https://image.tmdb.org/t/p/w1280\(movie.backdrop_path ?? "")")) { img in
                img.resizable().aspectRatio(contentMode: .fill)
            } placeholder: { Color.black }
            .frame(height: 650)
