```

#### B. Home Content Row (Spatial Grid)
```swift
struct HomeContentRow<T: Identifiable>: View {
    let title: String
    let items: [T]
    var isProgressRow: Bool = false

    var body: some View {
        VStack(alignment: .leading, spacing: 20) {
            HStack {
                Rectangle()
                    .fill(.red)
                    .frame(width: 4, height: 24)
