                                    .foregroundStyle(.red)

                                Text("DOUBLAJ")
                                    .font(.system(size: 45, weight: .black, design: .rounded))
                                    .italic()
                                    .tracking(-2)
                            }
                            Spacer()
                            NodeCounter(count: viewModel.dubbedArchive.count)
                        }
                        .padding(.horizontal, 25)

                        LazyVGrid(columns: [GridItem(.flexible()), GridItem(.flexible())], spacing: 25) {
                            ForEach(viewModel.dubbedArchive) { item in
                                DubbedNodeCard(movie: item)
                            }
                        }
                        .padding(.horizontal, 25)
                    }
                    .padding(.top, -50) // Overlap with Hero
                    .padding(.bottom, 120)
                }
            }

            // Top Nav Controls
            HStack {
                Button { dismiss() } label: {
                    Image(systemName: "arrow.left")
                        .font(.title3.bold())
                        .padding(15)
                        .background(.ultraThinMaterial)
                        .clipShape(Circle())
                }
                Spacer()
            }
            .padding(.horizontal, 25)
            .padding(.top, 60)
            .frame(maxHeight: .infinity, alignment: .top)
        }
        .task { await viewModel.syncArchive() }
    }
}
```

